long long sumOfSubarrayRanges(vector<int>& inputArray) {
    int n = inputArray.size();
    vector<int> left(n), right(n);
    stack<int> st;

    // contribution as maximum
    for (int i = 0; i < n; i++) {
        while (!st.empty() && inputArray[st.top()] < inputArray[i]) st.pop();
        left[i] = st.empty() ? i + 1 : i - st.top();
        st.push(i);
    }

    while (!st.empty()) st.pop();

    for (int i = n - 1; i >= 0; i--) {
        while (!st.empty() && inputArray[st.top()] <= inputArray[i]) st.pop();
        right[i] = st.empty() ? n - i : st.top() - i;
        st.push(i);
    }

    long long maxSum = 0;
    for (int i = 0; i < n; i++)
        maxSum += 1LL * inputArray[i] * left[i] * right[i];

    // reset for minimum
    while (!st.empty()) st.pop();

    for (int i = 0; i < n; i++) {
        while (!st.empty() && inputArray[st.top()] > inputArray[i]) st.pop();
        left[i] = st.empty() ? i + 1 : i - st.top();
        st.push(i);
    }

    while (!st.empty()) st.pop();

    for (int i = n - 1; i >= 0; i--) {
        while (!st.empty() && inputArray[st.top()] >= inputArray[i]) st.pop();
        right[i] = st.empty() ? n - i : st.top() - i;
        st.push(i);
    }

    long long minSum = 0;
    for (int i = 0; i < n; i++)
        minSum += 1LL * inputArray[i] * left[i] * right[i];

    return maxSum - minSum;
}

