long long sumOfSubarrayRanges(int* inputArray, int n) {
    int left[n], right[n], stack[n], top = -1;

    // contribution as maximum
    for (int i = 0; i < n; i++) {
        while (top >= 0 && inputArray[stack[top]] < inputArray[i]) top--;
        left[i] = (top < 0) ? i + 1 : i - stack[top];
        stack[++top] = i;
    }

    top = -1;

    for (int i = n - 1; i >= 0; i--) {
        while (top >= 0 && inputArray[stack[top]] <= inputArray[i]) top--;
        right[i] = (top < 0) ? n - i : stack[top] - i;
        stack[++top] = i;
    }

    long long maxSum = 0;
    for (int i = 0; i < n; i++)
        maxSum += (long long)inputArray[i] * left[i] * right[i];

    // reset for minimum
    top = -1;

    for (int i = 0; i < n; i++) {
        while (top >= 0 && inputArray[stack[top]] > inputArray[i]) top--;
        left[i] = (top < 0) ? i + 1 : i - stack[top];
        stack[++top] = i;
