class Codechef {

    public long sumOfSubarrayRanges(int[] inputArray) {
            int n = inputArray.length;
            long totalSum = 0;

            int[] prevGreater = new int[n];
            int[] nextGreater = new int[n];
            int[] prevSmaller = new int[n];
            int[] nextSmaller = new int[n];
            Stack<Integer> s = new Stack<>();

            // 1. Previous Greater (Strictly Greater)
            for (int i = 0; i < n; i++) {
                while (!s.isEmpty() && inputArray[s.peek()] <= inputArray[i]) {
                    s.pop();
                }
                prevGreater[i] = s.isEmpty() ? -1 : s.peek();
                s.push(i);
            }
            s.clear();

            // 2. Next Greater (Greater or Equal)
            for (int i = n - 1; i >= 0; i--) {
                while (!s.isEmpty() && inputArray[s.peek()] < inputArray[i]) {
                    s.pop();
                }
                nextGreater[i] = s.isEmpty() ? n : s.peek();
                s.push(i);
            }
            s.clear();

            // 3. Previous Smaller (Strictly Smaller)
            for (int i = 0; i < n; i++) {
                while (!s.isEmpty() && inputArray[s.peek()] >= inputArray[i]) {
                    s.pop();
                }
                prevSmaller[i] = s.isEmpty() ? -1 : s.peek();
                s.push(i);
            }
            s.clear();

            // 4. Next Smaller (Smaller or Equal)
            for (int i = n - 1; i >= 0; i--) {
                while (!s.isEmpty() && inputArray[s.peek()] > inputArray[i]) {
                    s.pop();
                }
                nextSmaller[i] = s.isEmpty() ? n : s.peek();
                s.push(i);
            }

            // Calculate total sum
            for (int i = 0; i < n; i++) {
                long leftMax = i - prevGreater[i];
                long rightMax = nextGreater[i] - i;
                long leftMin = i - prevSmaller[i];
                long rightMin = nextSmaller[i] - i;

                totalSum += (leftMax * rightMax - leftMin * rightMin) * (long)inputArray[i];
            }
            return totalSum;
        }
    }

